"use client";

import { useMemo, useRef, useState, useEffect } from "react";
import { DeptHeader } from "@/components/shared/DeptHeader";
import { AIStrip } from "@/components/shared/AIStrip";
import { PeriodTabs } from "@/components/shared/PeriodTabs";
import { SectionLabel } from "@/components/shared/SectionLabel";
import { CapitalCalendar } from "@/features/ops/components/CapitalCalendar";
import { BridgePrimaryButton } from "@/features/bridge/components/BridgePrimaryButton";
import {
  CAP_ITEMS,
  CAP_START,
  CAP_FLOOR,
  CAP_REC,
  CAP_BULK_ADD,
  VERDICT_COLOR,
  VERDICT_ORDER,
  capHorizonAI,
  type Verdict,
} from "@/features/ops/api/ops-capital-horizon-data";
import "./capital-horizon.css";

const fmtK = (v: number) => `$${Math.round(v / 1000)}K`;

const PROD_ICONS: Record<string, React.ReactNode> = {
  vase: <svg viewBox="0 0 32 32" fill="none" stroke="#0d2137" strokeWidth="1.4" strokeLinejoin="round"><path d="M11 14 Q9 21.5 12.5 26.5 L19.5 26.5 Q23 21.5 21 14 Z" fill="rgba(216,90,48,0.12)" /><path d="M11 14 H21" /><path d="M13 14 V11 H19 V14" /></svg>,
  screen: <svg viewBox="0 0 32 32" fill="none" stroke="#0d2137" strokeWidth="1.4" strokeLinejoin="round"><rect x="9" y="4" width="14" height="24" rx="2.6" fill="rgba(91,124,176,0.13)" /><line x1="13" y1="25" x2="19" y2="25" /></svg>,
  box: <svg viewBox="0 0 32 32" fill="none" stroke="#0d2137" strokeWidth="1.4" strokeLinejoin="round"><path d="M6 11 L16 6 L26 11 L16 16 Z" fill="rgba(216,90,48,0.12)" /><path d="M6 11 V22 L16 27 V16" /><path d="M26 11 V22 L16 27" /></svg>,
  roses: <svg viewBox="0 0 32 32" fill="none" stroke="#0d2137" strokeWidth="1.3" strokeLinejoin="round"><circle cx="12" cy="9" r="3.1" fill="rgba(212,83,126,0.42)" /><circle cx="19.5" cy="8" r="2.9" fill="rgba(212,83,126,0.42)" /><circle cx="16" cy="13" r="2.9" fill="rgba(212,83,126,0.42)" /><path d="M12 12 L15 22 M19.5 11 L16.5 22 M16 16 L16 24" stroke="#1D9E75" /></svg>,
  cable: <svg viewBox="0 0 32 32" fill="none" stroke="#0d2137" strokeWidth="1.4" strokeLinecap="round" strokeLinejoin="round"><rect x="13" y="4" width="6" height="5.2" rx="1.6" fill="rgba(91,124,176,0.2)" /><path d="M16 9.2 C16 14 9 14 9 19 C9 24 16 23 16 27.5" /></svg>,
  giftset: <svg viewBox="0 0 32 32" fill="none" stroke="#0d2137" strokeWidth="1.4" strokeLinejoin="round"><rect x="7" y="13" width="18" height="14" rx="1.5" fill="rgba(216,90,48,0.10)" /><path d="M16 13 V27" /><path d="M7 18 H25" /></svg>,
  dye: <svg viewBox="0 0 32 32" fill="none" stroke="#0d2137" strokeWidth="1.4" strokeLinejoin="round"><path d="M13 4 H19 V8 L21 11 V25.5 A1.2 1.2 0 0 1 19.8 26.7 H12.2 A1.2 1.2 0 0 1 11 25.5 V11 L13 8 Z" fill="rgba(214,69,69,0.14)" /><path d="M11 17 H21" /></svg>,
  stand: <svg viewBox="0 0 32 32" fill="none" stroke="#0d2137" strokeWidth="1.4" strokeLinejoin="round"><rect x="8" y="5" width="16" height="12" rx="1.5" fill="rgba(176,172,162,0.2)" /><path d="M16 17 V23" /><path d="M10 27 L16 23 L22 27" /></svg>,
};

type SortKey = "rank" | "name" | "onhand" | "vel" | "runway" | "cost" | "verdict";
const DEFAULT_SORT_DIR: Record<SortKey, "asc" | "desc"> = {
  rank: "asc",
  name: "asc",
  onhand: "desc",
  vel: "desc",
  runway: "asc",
  cost: "desc",
  verdict: "asc",
};

export default function CapitalHorizonPage() {
  const items = CAP_ITEMS;
  const orders = useMemo(() => items.filter((i) => i.kind === "order"), [items]);

  const [horizon, setHorizon] = useState(90);
  const [count, setCount] = useState(CAP_REC);
  const [bulk, setBulk] = useState(false);
  const [verdictFilter, setVerdictFilter] = useState<"all" | Verdict>("all");
  const [search, setSearch] = useState("");
  const [sortKey, setSortKey] = useState<SortKey>("rank");
  const [sortDir, setSortDir] = useState<"asc" | "desc">("asc");
  const [selectedIdx, setSelectedIdx] = useState<number | null>(null);
  const [rowBridgeSent, setRowBridgeSent] = useState<string | null>(null);

  const VERDICT_LABEL: Record<Verdict, string> = {
    reorder: "Place order",
    watch: "Watch",
    hold: "Hold",
    liquidate: "Liquidate",
  };
  const sendRowBridge = (sku: string) => {
    setRowBridgeSent(sku);
    setTimeout(() => setRowBridgeSent(null), 1500);
  };

  // Compute plan totals
  const included = useMemo(
    () =>
      orders.slice(0, count).map((o) => ({
        ...o,
        cost: o.base + (o.bulk && bulk ? CAP_BULK_ADD : 0),
      })),
    [orders, count, bulk]
  );
  const totalOut = included.reduce((a, b) => a + b.cost, 0);
  const bal = CAP_START - totalOut;
  const margin = bal - CAP_FLOOR;
  const danger = bal < CAP_FLOOR;
  const tight = !danger && margin < 50_000;

  // Slider chrome positions
  const sliderRef = useRef<HTMLDivElement | null>(null);
  const [sliderW, setSliderW] = useState(760);
  useEffect(() => {
    if (!sliderRef.current) return;
    const ro = new ResizeObserver(() => {
      if (sliderRef.current) setSliderW(sliderRef.current.clientWidth);
    });
    ro.observe(sliderRef.current);
    setSliderW(sliderRef.current.clientWidth);
    return () => ro.disconnect();
  }, []);
  const max = orders.length;
  // Floor-tick position: how many orders can be placed before crossing the floor
  const floorCount = useMemo(() => {
    let b = CAP_START;
    let fc = 0;
    for (let i = 0; i < max; i++) {
      if (b - orders[i].base < CAP_FLOOR) break;
      b -= orders[i].base;
      fc = i + 1;
    }
    return fc;
  }, [orders, max]);
  const handlePx = (count / max) * sliderW;
  const recPx = (CAP_REC / max) * sliderW;
  const floorPx = (floorCount / max) * sliderW;

  // Filter + sort ledger rows
  const rows = useMemo(() => {
    let list = items.slice();
    if (verdictFilter !== "all") list = list.filter((i) => i.verdict === verdictFilter);
    if (search) list = list.filter((i) => (i.name + " " + i.sku).toLowerCase().includes(search.toLowerCase()));
    const dir = sortDir === "asc" ? 1 : -1;
    list.sort((a, b) => {
      let av: number, bv: number;
      switch (sortKey) {
        case "name":
          return dir * a.name.localeCompare(b.name);
        case "onhand":
          av = a.onhand; bv = b.onhand;
          break;
        case "vel":
          av = a.vel; bv = b.vel;
          break;
        case "runway":
          av = a.runway; bv = b.runway;
          break;
        case "cost":
          av = a.base + (a.bulk && bulk ? CAP_BULK_ADD : 0);
          bv = b.base + (b.bulk && bulk ? CAP_BULK_ADD : 0);
          break;
        case "verdict":
          av = VERDICT_ORDER[a.verdict]; bv = VERDICT_ORDER[b.verdict];
          break;
        default:
          av = a.rank; bv = b.rank;
      }
      return dir * (av - bv);
    });
    return list;
  }, [items, verdictFilter, search, sortKey, sortDir, bulk]);

  const handleSort = (k: SortKey) => {
    if (k === sortKey) setSortDir((d) => (d === "asc" ? "desc" : "asc"));
    else {
      setSortKey(k);
      setSortDir(DEFAULT_SORT_DIR[k]);
    }
  };

  // Argument text (italic Fraunces) — adapts to slider state
  const argHtml = (() => {
    if (danger) {
      return `This plan punches through the floor by <b>${fmtK(Math.abs(margin))}</b>. That's tax and payroll money. Magellan will let you commit it — it's your call — but the Bridge will flag it. <b>Defer or stagger an order</b> before you place.`;
    }
    if (count <= 2) {
      return `Ordering only ${count} leaves <b>the structural reorders</b> unprotected — their runway is shorter than their lead time, so they stock out before any later order can land. <b>Pull the handle right</b> to cover them.`;
    }
    if (count <= CAP_REC) {
      return `Magellan holds here: the <b>${count} urgent reorders</b> that would otherwise stock out, placed now for <b>${fmtK(totalOut)}</b>, leaving <b>${fmtK(bal)}</b> — a comfortable <b>${fmtK(margin)}</b> above the floor. The rest can wait for the next cash cycle.`;
    }
    if (tight) {
      return `Pulling in the Watch items spends <b>${fmtK(totalOut)}</b> and leaves only <b>${fmtK(margin)}</b> of margin — survivable, but it ties up cash these SKUs don't urgently need. Worth it only if you expect a demand spike.`;
    }
    return `Every reorder placed: <b>${fmtK(totalOut)}</b> out, <b>${fmtK(bal)}</b> left. Still clear of the floor, but you've committed cash to SKUs with 15–22 days of runway — money that could sit in the bank or go to ads until they actually need it.`;
  })();

  const argMkColor = danger ? "#d64545" : count <= 2 ? "#d64545" : count <= CAP_REC ? "#1D9E75" : tight ? "#cf7d1f" : "#D85A30";

  // Console body texts
  const exposureHtml = danger
    ? `Placing <b>${count} orders</b> sends <b>${fmtK(totalOut)}</b> out of the bank — deployable cash falls to <b>${fmtK(bal)}</b>, <span class="red">${fmtK(Math.abs(margin))} below the $120K floor</span>. The tightest week is day 12, when packaging and the bestseller restock land together.`
    : `Placing <b>${count} orders</b> sends <b>${fmtK(totalOut)}</b> out of the bank — deployable cash falls to <b>${fmtK(bal)}</b>, <b>${fmtK(margin)}</b> above the $120K floor. The tightest week is day 12, when the lumpy packaging order lands.`;
  const directiveText = (() => {
    if (danger) return "Hold the bulk-buy or defer the two Watch items — either move pulls you back above the floor. Place the 4 structural reorders now ($147K); they're the ones that stock out otherwise.";
    if (count <= 2) return "Place at least the 4 structural reorders now — Cylinder Vase and Screen Protector are already past the point of no return. Deferring them means lost sales, not saved cash.";
    if (count <= CAP_REC) return `Place the ${count} urgent reorders now ($${Math.round(totalOut / 1000)}K). Defer USB-C and Gift Set to the next cycle. Hold Fabric Dye — 30 days of cover. Liquidate the Vintage Display Stand to recover $2.7K.`;
    if (tight) return "Acceptable, but stagger the Watch items by two weeks if you can — same coverage, more cash breathing room through the tight week.";
    return "You can place everything and stay solvent, but consider holding the 15–22-day-runway SKUs — that cash works harder in the bank or in ads until they're actually needed.";
  })();

  return (
    <div className="ops-capital-horizon-page">
      <DeptHeader
        dept="ops"
        title="Capital Horizon"
        meta={<><span className="live">Live</span> · Next 90 days · 6 reorders pending</>}
        actions={
          <>
            <button className="btn-util">Export plan</button>
            <BridgePrimaryButton dept="ops" page="replenishment-plan">Place orders → Bridge</BridgePrimaryButton>
          </>
        }
      />

      <PeriodTabs
        labels={["Next 30 days", "Next 60 days", "Next 90 days"]}
        activeIndex={horizon === 30 ? 0 : horizon === 60 ? 1 : 2}
        onChange={(i) => setHorizon([30, 60, 90][i])}
        marginBottom={20}
      />

      {/* METRIC STRIP */}
      <div className="metric-strip">
        <div className="metric">
          <div className="metric-l">Deployable cash</div>
          <div className="metric-v">{fmtK(CAP_START)}</div>
          <div className="metric-s">after tax + payroll reserve</div>
        </div>
        <div className="metric">
          <div className="metric-l">Must order now</div>
          <div className="metric-v ops">6 SKUs</div>
          <div className="metric-s down">$84K revenue at risk</div>
        </div>
        <div className="metric">
          <div className="metric-l">After this plan</div>
          <div className={`metric-v ${danger ? "red" : "green"}`}>{fmtK(bal)}</div>
          <div className="metric-s">
            {fmtK(totalOut)} deployed · {count} order{count !== 1 ? "s" : ""}
          </div>
        </div>
        <div className="metric">
          <div className="metric-l">Floor margin</div>
          <div className={`metric-v ${danger ? "red" : tight ? "ops" : ""}`}>
            {danger ? "−" + fmtK(Math.abs(margin)) : fmtK(margin)}
          </div>
          <div className="metric-s">{danger ? "below $120K floor" : "above $120K liquidity floor"}</div>
        </div>
        <div className="metric">
          <div className="metric-l">First stockout</div>
          <div className="metric-v">2 days</div>
          <div className="metric-s">Cylinder Vase · 0 on hand</div>
        </div>
      </div>

      {/* AI STRIP */}
      <AIStrip label={capHorizonAI.label} meta={capHorizonAI.meta} cards={capHorizonAI.cards} />

      {/* CAPITAL CALENDAR */}
      <SectionLabel>The capital calendar — what leaves the bank, and what's left</SectionLabel>
      <div className="card">
        <div className="c-head">
          <div>
            <div className="c-k">Deployable cash · next {horizon} days</div>
            <div className="c-hero">
              <span className="big">{fmtK(CAP_START)}</span>
              <span className="d">today · before orders</span>
            </div>
            <div className="c-sub">Each drop = a reorder leaving the bank · red line = $120K liquidity floor</div>
          </div>
          <div className="cluster">
            <div className="live-row">
              <span className="live-dot" />
              <span className="lt">Live <span>· ledger + cash</span></span>
            </div>
            <div className="verified">
              <svg width="20" height="20" viewBox="0 0 22 22" fill="none">
                <rect x="2.5" y="2.5" width="17" height="17" rx="1" stroke="#5B7CB0" strokeWidth="1.4" />
                <path d="M6.5 11.2l3 3L16 7.5" stroke="#5B7CB0" strokeWidth="1.8" strokeLinecap="square" />
              </svg>
              <div className="vt">
                <b>Reconciled</b>
                <span>opening balance seeded</span>
              </div>
            </div>
          </div>
        </div>

        <CapitalCalendar
          items={items}
          count={count}
          bulk={bulk}
          horizon={horizon}
          selectedIdx={selectedIdx}
          onItemSelect={(i) => setSelectedIdx(selectedIdx === i ? null : i)}
        />

        {/* PRIORITIZER */}
        <div className="prioritizer">
          <div className="prio-head">
            <div className="prio-title">
              The prioritizer
              <span className="prio-rec">Opens at Magellan's hold</span>
            </div>
            <div className="prio-readout">
              <div className="pr-block">
                <span className="pr-l">Orders now</span>
                <span className="pr-v">{count}</span>
              </div>
              <div className="pr-block">
                <span className="pr-l">Cash out</span>
                <span className="pr-v ops">{fmtK(totalOut)}</span>
              </div>
              <div className="pr-block">
                <span className="pr-l">After plan</span>
                <span className={`pr-v ${danger ? "red" : "green"}`}>{fmtK(bal)}</span>
              </div>
              <div className="pr-block">
                <span className="pr-l">Floor margin</span>
                <span className={`pr-v ${danger ? "red" : tight ? "ops" : "green"}`}>
                  {danger ? "−" + fmtK(Math.abs(margin)) + " under" : fmtK(margin) + " above"}
                </span>
              </div>
            </div>
          </div>

          <div className="slider-wrap" ref={sliderRef}>
            <div className="slider-track" />
            <div className={`slider-fill${danger ? " danger" : tight ? " warn" : ""}`} style={{ width: handlePx }} />
            {Array.from({ length: max }, (_, i) => (
              <div key={i} className="notch" style={{ left: ((i + 1) / max) * sliderW }} />
            ))}
            <div className="rec-tick" style={{ left: recPx }} />
            <div className="floor-tick" style={{ left: floorPx }} />
            <div
              className={`slider-handle${danger ? " danger" : ""}`}
              style={{ left: handlePx }}
            />
            <input
              type="range"
              className="slider-input"
              min={0}
              max={max}
              step={1}
              value={count}
              onChange={(e) => setCount(+e.target.value)}
              aria-label="How many reorders to place now"
            />
          </div>
          <div className="slider-scale">
            <span>Order nothing</span>
            <span>Place every reorder</span>
          </div>

          <button className={`bulk-toggle${bulk ? " on" : ""}`} onClick={() => setBulk(!bulk)}>
            <span className="bulk-box">
              <svg viewBox="0 0 24 24" fill="none" stroke="#fff" strokeWidth="3">
                <path d="M5 12l5 5L20 6" />
              </svg>
            </span>
            <span className="bulk-txt">
              Bulk-buy packaging — <b>12 months</b> for a unit discount (+$55K now)
            </span>
          </button>
        </div>

        <div className="argument">
          <span className="mk" style={{ background: argMkColor }} />
          <p dangerouslySetInnerHTML={{ __html: argHtml }} />
        </div>
      </div>

      {/* REPLENISHMENT LEDGER */}
      <SectionLabel>Replenishment ledger — ranked by depletion risk</SectionLabel>
      <div className="ldg-tools">
        <div className="pt-search">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8">
            <circle cx="11" cy="11" r="7" />
            <path d="M21 21l-4.3-4.3" />
          </svg>
          <input
            type="text"
            placeholder="Search SKUs by name or code…"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
        </div>
        <div className="filters">
          {(["all", "reorder", "watch", "hold", "liquidate"] as const).map((v) => (
            <button
              key={v}
              className={`fchip${verdictFilter === v ? " active" : ""}`}
              onClick={() => setVerdictFilter(v)}
            >
              {v === "all" ? "All" : v.charAt(0).toUpperCase() + v.slice(1)}
            </button>
          ))}
        </div>
      </div>

      <div className="ledger">
        <div className="ldg-head">
          <span />
          <span className="th" onClick={() => handleSort("rank")}>#</span>
          <span className="th" onClick={() => handleSort("name")}>SKU · landed cost</span>
          <span className="th num" onClick={() => handleSort("onhand")}>On hand</span>
          <span className="th num" onClick={() => handleSort("vel")}>Velocity</span>
          <span className="th num" onClick={() => handleSort("runway")}>Runway / lead</span>
          <span className="th num" onClick={() => handleSort("cost")}>Reorder cost</span>
          <span className="th num" onClick={() => handleSort("verdict")}>Verdict</span>
        </div>

        {rows.length === 0 ? (
          <div className="ldg-empty">No SKUs match this filter</div>
        ) : (
          rows.map((o) => {
            const isOrder = o.kind === "order";
            const includedRow = isOrder && o.rank < count;
            const cost = o.base + (o.bulk && bulk ? CAP_BULK_ADD : 0);
            const alarm = isOrder && o.runway < o.lead;
            const rowCls = isOrder ? (includedRow ? "" : "deferred") : o.verdict;
            const runwayTxt = o.runway > 365 ? "∞" : o.runway === 0 ? "0d" : o.runway + "d";
            const leadTxt = o.lead ? `lead ${o.lead}d${alarm ? " · short" : ""}` : "—";
            const origIdx = items.indexOf(o);
            return (
              <div
                key={o.sku}
                className={`ldg-row ${rowCls}${selectedIdx === origIdx ? " sel" : ""}`}
                style={{ ["--vstripe" as string]: VERDICT_COLOR[o.verdict] } as React.CSSProperties}
                onClick={() => setSelectedIdx(selectedIdx === origIdx ? null : origIdx)}
              >
                <div className="ldg-thumb">{PROD_ICONS[o.prod]}</div>
                <div className="ldg-rank">{String(o.rank + 1).padStart(2, "0")}</div>
                <div>
                  <div className="ldg-name">{o.name}</div>
                  <div className="ldg-sub">
                    {o.sku}
                    {o.bulk && bulk && includedRow ? " · 12-mo bulk" : ""}
                    {o.note ? ` · ${o.note}` : ""}
                  </div>
                </div>
                <div>
                  <div className="ldg-num">{o.onhandT}</div>
                  <div className="ldg-numsub">{o.unit}</div>
                </div>
                <div>
                  <div className="ldg-num muted">{o.velT}</div>
                </div>
                <div>
                  <div className="ldg-num">{runwayTxt}</div>
                  <div className={`ldg-numsub${alarm ? " alarm" : ""}`}>{leadTxt}</div>
                </div>
                <div>
                  {isOrder ? (
                    <>
                      <div className={`ldg-cost ${includedRow ? "in" : "out"}`}>{fmtK(cost)}</div>
                      <div className={`ldg-state${includedRow ? " placing" : ""}`}>
                        {includedRow ? "placing now" : "deferred"}
                      </div>
                    </>
                  ) : (
                    <>
                      <div className="ldg-cost out">{o.verdict === "liquidate" ? "recover $2.7K" : "$0"}</div>
                      <div className="ldg-state">{o.verdict === "hold" ? "hold — no order" : "liquidate"}</div>
                    </>
                  )}
                </div>
                <div className="ldg-verdict">
                  <span className={`vpill ${o.verdict}`}>{o.verdict}</span>
                </div>
                <button
                  className={`ldg-bridge${rowBridgeSent === o.sku ? " sent" : ""}`}
                  onClick={(e) => {
                    e.stopPropagation();
                    sendRowBridge(o.sku);
                  }}
                >
                  {rowBridgeSent === o.sku ? `${VERDICT_LABEL[o.verdict]} sent ✓` : (
                    <>
                      {VERDICT_LABEL[o.verdict]}
                      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                        <line x1="5" y1="12" x2="19" y2="12" />
                        <polyline points="12 5 19 12 12 19" />
                      </svg>
                    </>
                  )}
                </button>
              </div>
            );
          })
        )}
      </div>

      {/* CONSOLE NOTE */}
      <section className="console">
        <div className="console-label">
          <span style={{ width: 18, height: 18, borderRadius: 4, background: "var(--cream)", color: "var(--navy-deep)", display: "inline-flex", alignItems: "center", justifyContent: "center", fontFamily: "Inter", fontSize: 11, fontWeight: 600 }}>
            M
          </span>
          Console note
        </div>
        <div className="console-row">
          <div className="console-tag read">Read</div>
          <div className="console-body">
            Deployable cash <b>{fmtK(CAP_START)}</b>, net of tax and payroll reserve. 6 SKUs are below their reorder trigger; the liquidity floor is <b>$120K</b> — the cash you must never spend.
          </div>
        </div>
        <div className="console-row">
          <div className="console-tag exposure">Exposure</div>
          <div className="console-body" dangerouslySetInnerHTML={{ __html: exposureHtml }} />
        </div>
        <div className="console-row">
          <div className="console-tag directive">Directive</div>
          <div className="console-body">{directiveText}</div>
        </div>
      </section>
    </div>
  );
}
