export type OrderKind = "order" | "passive";
export type Verdict = "reorder" | "watch" | "hold" | "liquidate";

export interface CapItem {
  /** Product icon key */
  prod: string;
  /** Rank by depletion risk (0 = most urgent) */
  rank: number;
  kind: OrderKind;
  name: string;
  /** "SKU-3021 · $76" */
  sku: string;
  /** Day the order would land (only for kind="order") */
  day?: number;
  /** Base reorder cost */
  base: number;
  /** Eligible for 12-month bulk-buy (adds $55K) */
  bulk: boolean;
  onhand: number;
  onhandT: string;
  unit: string;
  vel: number;
  velT: string;
  /** Runway in days */
  runway: number;
  lead: number;
  verdict: Verdict;
  note?: string;
}

