"use client";

/* ════════════════════════════════════════════════════════════════════════
   CapitalCalendar — Operations Tier-1 instrument.

   Question it answers: "Where will my deployable cash be over the next N
   days, and which reorders pull it down?" — a horizontal cash trajectory
   with each reorder shown as a vertical "drop", a red liquidity floor,
   today beacon at left, and end-of-horizon value chip on the right.
   Hover anywhere → tooltip showing day + deployable cash at that day.

   Per Chart Standard §2: useChartSize (true-px text), typed data, hero
   readable without hover, 4 states, reduced-motion safe.
   ════════════════════════════════════════════════════════════════════════ */

import { useEffect, useMemo, useRef, useState } from "react";
import { useChartSize, usePrefersReducedMotion } from "@/lib/useChartSize";
import {
  CAP_START,
  CAP_FLOOR,
  VERDICT_COLOR,
  type CapItem,
} from "@/features/ops/api/ops-capital-horizon-data";

export type ChartState = "ready" | "loading" | "empty" | "error";

export interface CapitalCalendarProps {
  /** All reorder candidates */
  items: CapItem[];
  /** Number of items (from rank 0) to include in the active plan */
  count: number;
  /** Whether the bulk-buy is on (adds $55K to bulk-eligible items) */
  bulk: boolean;
  /** Horizon in days (30 / 60 / 90) */
  horizon: number;
  /** Selected item index in the original items array (for ring highlight) */
  selectedIdx: number | null;
  onItemSelect?: (idx: number) => void;
  state?: ChartState;
}

const BULK_ADD = 55_000;
const VBH = 320;
const PAD_L = 8;
const PAD_R_INSET = 12;
const PLOT_T = 26;
const PLOT_B = 250;
const CASH_MAX = 400_000;
const CASH_MIN = 80_000;

const fmtK = (v: number) => `$${Math.round(v / 1000)}K`;

export function CapitalCalendar({
  items,
  count,
  bulk,
  horizon,
  selectedIdx,
  onItemSelect,
  state = "ready",
}: CapitalCalendarProps) {
  const { ref, width: VBW } = useChartSize({ min: 640, fallback: 980 });
  const reduce = usePrefersReducedMotion();
  const svgRef = useRef<SVGSVGElement | null>(null);
  const [hoverX, setHoverX] = useState<number | null>(null);
  const [drawn, setDrawn] = useState(reduce);

  useEffect(() => {
    if (reduce) {
      setDrawn(true);
      return;
    }
    const r = requestAnimationFrame(() => requestAnimationFrame(() => setDrawn(true)));
    return () => cancelAnimationFrame(r);
  }, [reduce]);

  const PR = VBW - PAD_R_INSET;
  const x = (d: number) => PAD_L + (d / horizon) * (PR - PAD_L);
  const y = (c: number) => PLOT_T + ((CASH_MAX - c) / (CASH_MAX - CASH_MIN)) * (PLOT_B - PLOT_T);

  const orders = useMemo(() => items.filter((i) => i.kind === "order"), [items]);

  /** Items currently included in the plan, with bulk-adjusted cost */
  const included = useMemo(
    () =>
      orders.slice(0, count).map((o) => ({
        ...o,
        cost: o.base + (o.bulk && bulk ? BULK_ADD : 0),
        _origIdx: items.indexOf(o),
      })),
    [orders, count, bulk, items]
  );
  const deferred = useMemo(() => orders.slice(count), [orders, count]);

  // Build the cash path: starts at CAP_START, drops at each included.day
  const pathPoints = useMemo(() => {
    let bal = CAP_START;
    const pts: { d: number; c: number }[] = [{ d: 0, c: bal }];
    const drops: { d: number; top: number; bot: number; o: typeof included[number] }[] = [];
    included
      .filter((o) => (o.day ?? 9999) <= horizon)
      .sort((a, b) => (a.day ?? 0) - (b.day ?? 0))
      .forEach((o) => {
        pts.push({ d: o.day ?? 0, c: bal });
        bal -= o.cost;
        pts.push({ d: o.day ?? 0, c: bal });
        drops.push({ d: o.day ?? 0, top: pts[pts.length - 2].c, bot: bal, o });
      });
    pts.push({ d: horizon, c: bal });
    return { pts, drops, endBal: bal };
  }, [included, horizon]);

  const { pts, drops, endBal } = pathPoints;
  const margin = endBal - CAP_FLOOR;
  const danger = endBal < CAP_FLOOR;
  const tight = !danger && margin < 50_000;
  const lineColor = danger ? "#d64545" : "#D85A30";

  // Deferred items rendered as ghost markers
  const ghosts = useMemo(
    () => deferred.filter((o) => (o.day ?? 9999) <= horizon),
    [deferred, horizon]
  );

  // States
  if (state !== "ready") {
    const msg =
      state === "loading" ? "Loading cash horizon…" : state === "error" ? "Couldn't load capital horizon." : "No active reorders to plan.";
    return (
      <div style={{ minHeight: 260, display: "flex", alignItems: "center", justifyContent: "center", color: "var(--ink-2)", fontFamily: "var(--font-mono)", fontSize: 11, letterSpacing: "0.08em" }}>
        {msg}
      </div>
    );
  }

  const linePathD = `M ${x(pts[0].d).toFixed(1)} ${y(pts[0].c).toFixed(1)} ` + pts.map((p) => `L ${x(p.d).toFixed(1)} ${y(p.c).toFixed(1)}`).join(" ");
  const areaPathD = linePathD + ` L ${x(horizon).toFixed(1)} ${PLOT_B} L ${x(0).toFixed(1)} ${PLOT_B} Z`;

  // Hover: convert mouse x to day offset
  const handleMove = (e: React.MouseEvent) => {
    const svg = svgRef.current;
    if (!svg) return;
    const r = svg.getBoundingClientRect();
    const sx = ((e.clientX - r.left) / r.width) * VBW;
    setHoverX(sx);
  };
  const hoverDay = hoverX !== null ? Math.max(0, Math.min(horizon, ((hoverX - PAD_L) / (PR - PAD_L)) * horizon)) : null;
  const hoverBal = (() => {
    if (hoverDay === null) return null;
    let bal = CAP_START;
    included
      .filter((o) => (o.day ?? 9999) <= horizon)
      .sort((a, b) => (a.day ?? 0) - (b.day ?? 0))
      .forEach((o) => {
        if ((o.day ?? 0) <= hoverDay) bal -= o.cost;
      });
    return bal;
  })();

  // End-of-horizon chip
  const endX = x(horizon);
  const endY = y(endBal);
  const endLabelUp = endY < PLOT_T + 50;
  const chipY = endLabelUp ? endY + 12 : endY - 38;
  const lowCol = danger ? "#d64545" : tight ? "#cf7d1f" : "#1D9E75";

  return (
    <div ref={ref} style={{ position: "relative" }}>
      <svg
        ref={svgRef}
        viewBox={`0 0 ${VBW} ${VBH}`}
        style={{ display: "block", width: "100%", height: VBH, overflow: "visible" }}
        onMouseMove={handleMove}
        onMouseLeave={() => setHoverX(null)}
      >
        {/* Floor band */}
        <rect x={0} y={y(CAP_FLOOR)} width={PR} height={PLOT_B - y(CAP_FLOOR)} fill="#d64545" opacity={0.05} />
        {/* Gridlines + Y axis labels */}
        {[400_000, 300_000, 200_000, 120_000].map((c) => (
          <g key={c}>
            <line x1={0} y1={y(c)} x2={PR} y2={y(c)} stroke="rgba(0,0,0,0.05)" strokeWidth={1} />
            <text x={0} y={y(c) - 5} fontFamily="'JetBrains Mono', monospace" fontSize={11} fontWeight={500} letterSpacing="0.04em" fill={c === CAP_FLOOR ? "#d64545" : "#3d4047"}>
              {fmtK(c)}
            </text>
          </g>
        ))}
        {/* Floor line + tag */}
        <line x1={0} y1={y(CAP_FLOOR)} x2={PR} y2={y(CAP_FLOOR)} stroke="#d64545" strokeWidth={1.6} strokeDasharray="5 4" />
        <rect x={PR - 168} y={y(CAP_FLOOR) + 6} width={162} height={16} rx={2} fill="#d64545" />
        <text x={PR - 160} y={y(CAP_FLOOR) + 17} fontFamily="'JetBrains Mono', monospace" fontSize={9} fontWeight={600} letterSpacing="0.07em" fill="#fff">
          LIQUIDITY FLOOR · $120K
        </text>
        {/* X tick marks */}
        {Array.from({ length: 13 }, (_, i) => {
          const d = (i * horizon) / 12;
          const major = i % 4 === 0;
          return (
            <line
              key={i}
              x1={x(d)}
              y1={PLOT_B}
              x2={x(d)}
              y2={PLOT_B + (major ? 8 : 4)}
              stroke={`rgba(0,0,0,${major ? 0.3 : 0.12})`}
              strokeWidth={1}
            />
          );
        })}
        {/* X axis labels */}
        {[
          { d: 0, t: "Today", anchor: "start" as const, w: 600 },
          { d: Math.round(horizon / 3), t: `Day ${Math.round(horizon / 3)}`, anchor: "middle" as const, w: 500 },
          { d: Math.round((horizon * 2) / 3), t: `Day ${Math.round((horizon * 2) / 3)}`, anchor: "middle" as const, w: 500 },
          { d: horizon, t: `Day ${horizon}`, anchor: "end" as const, w: 500 },
        ].map((o) => (
          <text
            key={o.t}
            x={x(o.d)}
            y={PLOT_B + 24}
            fontFamily="'JetBrains Mono', monospace"
            fontSize={11}
            fontWeight={o.w}
            fill={o.d === 0 ? "#15171c" : "#3d4047"}
            letterSpacing="0.06em"
            textAnchor={o.anchor}
          >
            {o.t}
          </text>
        ))}

        {/* Area under cash line */}
        <path d={areaPathD} fill={lineColor} opacity={0.07} />

        {/* Deferred ghost markers */}
        {ghosts.map((o, i) => (
          <g key={`g-${o.sku}`}>
            <line x1={x(o.day ?? 0)} y1={PLOT_T + 8} x2={x(o.day ?? 0)} y2={PLOT_B} stroke="rgba(0,0,0,0.10)" strokeWidth={1} strokeDasharray="2 3" />
            <text x={x(o.day ?? 0)} y={PLOT_T + 4} fontFamily="'JetBrains Mono', monospace" fontSize={8.5} fill="#b0aca2" textAnchor="middle" letterSpacing="0.03em">
              deferred {fmtK(o.base)}
            </text>
          </g>
        ))}

        {/* Main cash line with draw-in animation */}
        <path
          d={linePathD}
          fill="none"
          stroke={lineColor}
          strokeWidth={2.4}
          strokeLinejoin="round"
          strokeLinecap="round"
          style={
            reduce
              ? undefined
              : {
                  strokeDasharray: 1600,
                  strokeDashoffset: drawn ? 0 : 1600,
                  transition: "stroke-dashoffset 1.5s cubic-bezier(.4,.1,.2,1) .2s",
                }
          }
        />

        {/* Drop markers */}
        {drops.map((dr, i) => {
          const col = VERDICT_COLOR[dr.o.verdict] || lineColor;
          const ly = y(dr.top) - 13;
          const anchor = dr.d < horizon * 0.08 ? "start" : dr.d > horizon * 0.86 ? "end" : "middle";
          const gapPx = i > 0 ? x(dr.d) - x(drops[i - 1].d) : 999;
          const showName = i > 0 && gapPx > 56 && dr.d > horizon * 0.05;
          return (
            <g
              key={`d-${dr.o.sku}`}
              style={{ cursor: onItemSelect ? "pointer" : "default" }}
              onClick={() => onItemSelect?.(dr.o._origIdx)}
            >
              <line x1={x(dr.d)} y1={y(dr.top)} x2={x(dr.d)} y2={y(dr.bot)} stroke={col} strokeWidth={3} strokeLinecap="round" />
              <rect x={x(dr.d) - 4} y={y(dr.bot) - 4} width={8} height={8} rx={1.5} fill="#fff" stroke={col} strokeWidth={1.6} />
              <text x={x(dr.d)} y={ly} fontFamily="'JetBrains Mono', monospace" fontSize={9.5} fontWeight={600} fill={col} textAnchor={anchor} letterSpacing="0.02em">
                −{fmtK(dr.o.cost)}
              </text>
              {showName && (
                <text x={x(dr.d)} y={ly + 11} fontFamily="'JetBrains Mono', monospace" fontSize={8} fill="#8a8d94" textAnchor={anchor} letterSpacing="0.04em">
                  {dr.o.name.split(" ")[0].toUpperCase()}
                </text>
              )}
              <circle cx={x(dr.d)} cy={y(dr.bot)} r={16} fill="transparent" />
            </g>
          );
        })}

        {/* End-of-horizon chip */}
        <rect x={endX - 150} y={chipY} width={142} height={30} rx={6} fill="#fffdf8" stroke="rgba(184,138,42,0.8)" strokeWidth={0.8} />
        <rect x={endX - 150} y={chipY} width={3} height={30} fill={danger ? "#d64545" : "#5B7CB0"} />
        <text x={endX - 140} y={chipY + 13} fontFamily="'JetBrains Mono', monospace" fontSize={7.5} fontWeight={600} letterSpacing="0.1em" fill="#8a8d94">
          {danger ? "BELOW FLOOR" : `AS OF DAY ${horizon}`}
        </text>
        <text x={endX - 140} y={chipY + 25} fontFamily="Inter, sans-serif" fontSize={12} fontWeight={500} fill={lowCol}>
          {danger ? "−" + fmtK(Math.abs(margin)) : fmtK(endBal)}
        </text>

        {/* TODAY pulsing beacon */}
        <g>
          {!reduce && (
            <>
              <circle cx={x(0)} cy={y(CAP_START)} r={5} fill="none" stroke="#5B7CB0" strokeWidth={1.4}>
                <animate attributeName="r" values="5;15" dur="2.3s" repeatCount="indefinite" />
                <animate attributeName="opacity" values="0.5;0" dur="2.3s" repeatCount="indefinite" />
              </circle>
              <circle cx={x(0)} cy={y(CAP_START)} r={5} fill="none" stroke="#5B7CB0" strokeWidth={1.4}>
                <animate attributeName="r" values="5;15" dur="2.3s" begin="1.15s" repeatCount="indefinite" />
                <animate attributeName="opacity" values="0.5;0" dur="2.3s" begin="1.15s" repeatCount="indefinite" />
              </circle>
            </>
          )}
          <circle cx={x(0)} cy={y(CAP_START)} r={4.5} fill="#5B7CB0" />
        </g>

        {/* Selection ring */}
        {selectedIdx !== null && (() => {
          const item = items[selectedIdx];
          if (!item || item.kind !== "order" || item.day === undefined || item.day > horizon) return null;
          const isIncluded = item.rank < count;
          const cy = isIncluded ? y(drops.find((d) => d.o.sku === item.sku)?.bot ?? CAP_START) : PLOT_T + 30;
          return <circle cx={x(item.day)} cy={cy} r={11} fill="none" stroke="#5B7CB0" strokeWidth={1.6} />;
        })()}

        {/* Hover crosshair */}
        {hoverDay !== null && hoverBal !== null && (
          <line x1={x(hoverDay)} y1={PLOT_T} x2={x(hoverDay)} y2={PLOT_B} stroke="#5B7CB0" strokeWidth={1} strokeDasharray="3 3" opacity={0.4} />
        )}
      </svg>

      {/* Tooltip */}
      {hoverDay !== null && hoverBal !== null && svgRef.current && (
        <div
          className="cal-tip"
          style={{
            display: "block",
            left: `${(x(hoverDay) / VBW) * 100}%`,
            top: `${(y(hoverBal) / VBH) * 100}%`,
          }}
        >
          <div className="tv">{fmtK(hoverBal)}</div>
          <div className="td">Day {Math.round(hoverDay)} · deployable</div>
        </div>
      )}
    </div>
  );
}
